const e=JSON.parse('{"key":"v-0d711272","path":"/basics/MySQL/%E5%9F%BA%E7%A1%80%E7%AF%87/3%E4%BA%8B%E5%8A%A1%E9%9A%94%E7%A6%BB.html","title":"事务隔离","lang":"zh-CN","frontmatter":{"author":"极客时间","date":"2022-05-25T00:00:00.000Z","category":["MySQL基础篇"],"summary":"事务隔离 提到事务，你肯定不陌生，和数据库打交道的时候，我们总是会用到事务。最经典的例子就是转账，你要给朋友小王转 100 块钱，而此时你的银行卡只有 100 块钱。 转账过程具体到程序里会有一系列的操作，比如查询余额、做加减法、更新余额等，这些操作必须保证是一体的，不然等程序查完之后，还没做减法之前，你这 100 块钱，完全可以借着这个时间差再查一次，然后","head":[["meta",{"property":"og:url","content":"https://vuepress-theme-hope-v2-demo.mrhope.site/basics/MySQL/%E5%9F%BA%E7%A1%80%E7%AF%87/3%E4%BA%8B%E5%8A%A1%E9%9A%94%E7%A6%BB.html"}],["meta",{"property":"og:site_name","content":"Weiser"}],["meta",{"property":"og:title","content":"事务隔离"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:updated_time","content":"2022-05-30T15:22:42.000Z"}],["meta",{"property":"og:locale","content":"zh-CN"}],["meta",{"property":"article:author","content":"极客时间"}],["meta",{"property":"article:published_time","content":"2022-05-25T00:00:00.000Z"}],["meta",{"property":"article:modified_time","content":"2022-05-30T15:22:42.000Z"}]]},"excerpt":"","headers":[{"level":2,"title":"隔离性与隔离级别","slug":"隔离性与隔离级别","link":"#隔离性与隔离级别","children":[]},{"level":2,"title":"事务隔离的实现","slug":"事务隔离的实现","link":"#事务隔离的实现","children":[]},{"level":2,"title":"事务的启动方式","slug":"事务的启动方式","link":"#事务的启动方式","children":[]},{"level":2,"title":"小结","slug":"小结","link":"#小结","children":[]},{"level":2,"title":"思考题","slug":"思考题","link":"#思考题","children":[]}],"git":{"createdTime":1653806451000,"updatedTime":1653924162000,"contributors":[{"name":"xwzbupt","email":"xwze@bupt.cn","commits":2}]},"readingTime":{"minutes":11.12,"words":3336},"filePathRelative":"basics/MySQL/基础篇/3事务隔离.md","localizedDate":"2022年5月25日"}');export{e as data};
